    const MODEL_LIMIT_CHARS = Math.floor(128000 * CHARS_PER_TOKEN);
    const existingChars = output.messages.reduce((sum, msg) => {
      return sum + (msg.parts?.reduce((s, p) => s + (p.text?.length ?? 0), 0) ?? 0);
    }, 0);
