// src/tools/knowledge-remove.ts
init_zod();
init_knowledge_store();
init_create_tool();
var knowledge_remove = createSwarmTool({
  description: "Delete an outdated swarm knowledge entry by ID (swarm tier only — does not affect hive). Double-deletion is idempotent — removing a non-existent entry returns a clear message without error.",
  args: {
    id: exports_external.string().min(1).describe("UUID of the knowledge entry to remove")
  },
  execute: async (args2, directory) => {
    let idInput;
    try {
      if (args2 && typeof args2 === "object") {
        const obj = args2;
        idInput = obj.id;
      }
    } catch {}
    if (typeof idInput !== "string" || idInput.length < 1) {
      return JSON.stringify({
        success: false,
        error: "id must be a non-empty string"
      });
    }
    const id = idInput;
    const swarmPath = resolveSwarmKnowledgePath(directory);
    let entries;
    try {
      entries = await readKnowledge(swarmPath);
    } catch (err2) {
      const message = err2 instanceof Error ? err2.message : "Unknown error";
      return JSON.stringify({
        success: false,
        error: message
      });
    }
    const originalCount = entries.length;
    entries = entries.filter((entry) => entry.id !== id);
    if (entries.length === originalCount) {
      return JSON.stringify({
        success: false,
        message: "entry not found"
      });
    }
    try {
      await rewriteKnowledge(swarmPath, entries);
    } catch (err2) {
      const message = err2 instanceof Error ? err2.message : "Unknown error";
      return JSON.stringify({
        success: false,
        error: message
      });
    }
    return JSON.stringify({
      success: true,
      removed: 1,
      remaining: entries.length
    });
  }
});

