import * as fs86 from "node:fs";
import * as path104 from "node:path";
var _gitignoreWarningEmitted = false;
function findGitRoot(startDir) {
  let current = startDir;
  while (true) {
    try {
      const gitPath = path104.join(current, ".git");
      const stat4 = fs86.statSync(gitPath);
      if (stat4.isDirectory()) {
        return current;
      }
    } catch {}
    const parent = path104.dirname(current);
    if (parent === current) {
      return null;
    }
    current = parent;
  }
}
function fileCoversSwarm(content) {
  for (const rawLine of content.split(`
`)) {
    const line = rawLine.trim();
    if (line.startsWith("#") || line.length === 0)
      continue;
    if (line === ".swarm" || line === ".swarm/")
      return true;
  }
  return false;
}
function readFileSafe(filePath) {
  try {
    return fs86.readFileSync(filePath, "utf8");
  } catch {
    return null;
  }
}
function warnIfSwarmNotGitignored(directory, quiet = false) {
  if (_gitignoreWarningEmitted)
    return;
  try {
    const gitRoot = findGitRoot(directory);
    if (!gitRoot)
      return;
    const gitignoreContent = readFileSafe(path104.join(gitRoot, ".gitignore"));
    if (gitignoreContent !== null && fileCoversSwarm(gitignoreContent)) {
      _gitignoreWarningEmitted = true;
      return;
    }
    const excludeContent = readFileSafe(path104.join(gitRoot, ".git", "info", "exclude"));
    if (excludeContent !== null && fileCoversSwarm(excludeContent)) {
      _gitignoreWarningEmitted = true;
      return;
    }
    _gitignoreWarningEmitted = true;
    if (!quiet) {
      console.warn('[opencode-swarm] WARNING: .swarm/ is not in your .gitignore. Shell audit logs may contain API keys. Add ".swarm/" to your .gitignore to prevent accidental commits.');
    }
  } catch {}
}

// src/utils/tool-output.ts
function truncateToolOutput(output, maxLines, toolName, tailLines = 10) {
  if (!output) {
    return output;
  }
  if (tailLines >= maxLines) {
    tailLines = Math.floor(maxLines / 2);
  }
  const lines = output.split(`
`);
  if (lines.length <= maxLines) {
    return output;
  }
  const omittedCount = lines.length - maxLines;
  const headLines = lines.slice(0, maxLines - tailLines);
  const tailContent = lines.slice(-tailLines);
  const footerLines = [];
  footerLines.push("");
  footerLines.push(`[... ${omittedCount} line${omittedCount === 1 ? "" : "s"} omitted ...]`);
  if (toolName) {
    footerLines.push(`Tool: ${toolName}`);
  }
  footerLines.push("Use /swarm retrieve <id> to get the full content");
  return `${headLines.join(`
`)}
${tailContent.join(`
`)}
${footerLines.join(`
`)}`;
}

